            if ((DM_?.coins || 0) < quantidade) return mention(`A quantidade que vocГӘ tem Г© inferior a que vocГӘ deseja transferir ao usuГЎrio: @${recebidor.split("@")[0]}`)
            if (!DM_2) return mention(`O(a) usuГЎrio(a) '@${recebidor.split("@")[0]}' nunca enviou uma mensagem neste grupo! EntГЈo nГЈo Г© possГӯvel adicionar ou transferir coins Г  um usuГЎrio nГЈo registrado no meu sistema!`);
            DM_["coins"] -= quantidade;
            DM_2["coins"] += quantidade;
            CoinsUpdate(RG_SCOINS);
