              // Pega a mensagem personalizada enviada pelo usuГЎrio
              var textoMensagem = q.trim();

              if (!textoMensagem) return reply('вқҢ Por favor, envie o texto que vocГӘ deseja enviar para os grupos!');

              // Verifica se hГЎ grupos na lista de grupos autorizados
