            if (!isGroup) return reply(mess.onlyGroup())
            if (!SoDono) return reply(mess.onlyOwner())
            if (!args[0]) return reply(`*бҙ…ЙӘЙўЙӘбҙӣбҙҮ бҙҸ бҙӣбҙҮбҙҚбҙҳбҙҸ бҙ…бҙҮ бҙҖКҹбҙңЙўбҙңбҙҮКҹ бҙҮбҙҚ бҙ…ЙӘбҙҖs. бҙҮx: ${prefix}бҙҖКҹбҙңЙўбҙңбҙҮКҹ 2 4 (2 бҙ…ЙӘбҙҖs бҙҮ 4 КңбҙҸКҖбҙҖs)* вҡ пёҸрҹҷҶвҖҚвҷӮпёҸ`)
            var dias = parseInt(args[0]) || 0
            var horas = parseInt(args[1]) || 0
            ativarAluguelGrupo(from, dias, horas)
            var agora = new Date()
