            if (!q || q.match(/[a-z]/i) || q.length > 3)
              return reply(`*бҙ…ЙӘЙўЙӘбҙӣбҙҮ бҙҖ З«бҙңбҙҖЙҙбҙӣЙӘбҙ…бҙҖбҙ…бҙҮ бҙҚЙӘЙҙЙӘбҙҚбҙҖ бҙҳбҙҖКҖбҙҖ КҖбҙҮбҙҚбҙҸбҙ бҙҮКҖ рҹӨ·вҖҚвҷӮпёҸ*\n*Exemplo:* ${prefix + command} 5`);
