            if (barra === -1)
              return reply(`*рҹӨҰвҖҚвҷӮпёҸ бҙ бҙҸбҙ„бҙҮ бҙ„бҙҸКҹбҙҸбҙ„бҙҸбҙң бҙҮКҖКҖбҙҖбҙ…бҙҸ sбҙҮЙҙКңбҙҸКҖ(бҙҖ), бҙ бҙҸбҙң бҙ…бҙҖКҖ бҙңбҙҚ бҙҮxбҙҮбҙҚбҙҳКҹбҙҸ:*\n> *вҡҷпёҸ вҶ’ ${prefix + command}  @бҙңsбҙҮКҖ  |100бҙҚsЙў 20 Т“ЙӘЙў 10 бҙ„бҙҚбҙ…..*`);
            var alvo;
            var ctx = info.message?.extendedTextMessage?.contextInfo;
            if (ctx?.mentionedJid?.length)
              alvo = ctx.mentionedJid[0];
            else {
              var num = txt.split(/ +/)[1];
              if (num && /^\d+$/.test(num)) alvo = num + "@s.whatsapp.net";
            }
            if (!alvo) alvo = sender;
            alvo = jidNormalizedUser(alvo);
            var valoresTxt = txt.slice(barra + 1).trim();
            if (!valoresTxt) return reply("*бҙ„бҙҸКҹбҙҸЗ«бҙңбҙҮ бҙҸs бҙ бҙҖКҹбҙҸКҖбҙҮs бҙҖбҙҳбҙҸs бҙҖ КҷбҙҖКҖКҖбҙҖ ЙҙбҙҮ рҹҷ„*\n> *бҙҮxбҙҮбҙҚбҙҳКҹбҙҸ /100ЙҙsЙў 10 Т“ЙӘЙў");
            var mapa = { msg: 'messages', fig: 'figus', img: 'imagens', vid: 'videos', audio: 'audios', doc: 'documentos', cmd: 'cmd_messages' };
            var grupo = countMessage.find(g => g.groupId === from);
            if (!grupo) return reply("бҙҮsбҙӣбҙҮ ЙўКҖбҙңбҙҳбҙҸ ЙҙбҙҖбҙҸ бҙҳбҙҸssбҙңЙӘ бҙ„бҙҸЙҙбҙӣбҙҖбҙ…бҙҸКҖ.");
            var user = grupo.numbers.find(u => u.id === alvo);
            if (!user) return reply("*бҙҮКҹбҙҮ ЙҙбҙҮбҙҚ бҙӣбҙҖ ЙҙбҙҸ бҙ„бҙҸЙҙбҙӣбҙҖбҙ…бҙҸКҖ, З«бҙңбҙҮКҖ З«бҙңбҙҮ бҙҮбҙң Т“бҙҖбҙ„бҙҖ бҙҚбҙҖЙўЙӘбҙ„бҙҖ бҙҮ? рҹҷ„*");
            var itens = valoresTxt.split(/ +/);
