            var resp = `*бҙ бҙҖКҹбҙҸКҖбҙҮs бҙҖбҙ…ЙӘбҙ„ЙӘбҙҸЙҙбҙҖбҙ…бҙҸs бҙҳбҙҖКҖбҙҖ @${alvo.split("@")[0]} бҙ„бҙҸбҙҚ sбҙңбҙ„бҙҮssбҙҸ рҹҷҮвҖҚвҷӮпёҸ*\n`;
            if (adicionados.length) resp += `*бҙҖбҙ…ЙӘбҙ„ЙӘбҙҸЙҙбҙҖбҙ…бҙҸs: ${adicionados.join(', ')} рҹ’Ҝ*`;
            if (invalidos.length) resp += `\n*ЙӘЙҙбҙ бҙҖКҹЙӘбҙ…бҙҸs: ${invalidos.join(', ')} вқ—*`;
            await corvo.sendMessage(from, { text: resp, contextInfo: { ...NkChannelKk, mentionedJid: [alvo] } }, { quoted: selo });
            break;
