            if (isJidBot(menc_os2)) return reply("*бҙҮбҙң sбҙҸбҙң бҙҖбҙҳбҙҮЙҙбҙҖs бҙңбҙҚбҙҖ бҙҚбҙҖЗ«бҙңЙӘЙҙбҙҖ З«бҙңбҙҮ ЙҙбҙҖбҙҸ бҙӣбҙҮбҙҚ sбҙҮЙҙбҙӣЙӘбҙҚбҙҮЙҙбҙӣбҙҸs.. ЙҙбҙҖбҙҸ бҙҳбҙҸssбҙҸ бҙҳКҖбҙҮбҙҮЙҙбҙ„КңбҙҮКҖ sбҙҮбҙң бҙ бҙҖбҙўЙӘбҙҸ, бҙҳбҙҮбҙ„бҙҖ бҙҖКҹЙўбҙңбҙҮбҙҚ КҖбҙҮбҙҖКҹ бҙҮбҙҚ ЙҙбҙҖбҙҚбҙҸКҖбҙҸ, бҙҮ ЙҙбҙҖбҙҸ бҙңбҙҚ КҖбҙҸКҷбҙҸ. рҹӨҰвҖҚвҷӮпёҸ*");
